import{_ as l,o as e,c as a,a2 as s}from"./chunks/framework.CMAFtOGK.js";const x=JSON.parse('{"title":"高等数学 · 考试大纲与考情","description":"广东专升本高数公开考纲范围对照","frontmatter":{"title":"高等数学 · 考试大纲与考情","description":"广东专升本高数公开考纲范围对照"},"headers":[],"relativePath":"posts/math/notes/syllabus.md","filePath":"posts/math/notes/syllabus.md","lastUpdated":1784753089000}'),r={name:"posts/math/notes/syllabus.md"};function n(o,t,i,d,g,h){return e(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="高等数学-·-考试大纲与考情" tabindex="-1">高等数学 · 考试大纲与考情 <a class="header-anchor" href="#高等数学-·-考试大纲与考情" aria-label="Permalink to &quot;高等数学 · 考试大纲与考情&quot;">​</a></h1><blockquote><p>广东普通专升本专业基础课《高等数学》公开考纲范围摘要 参考书：同济《高等数学》；以<strong>当年省考试院文件</strong>为准</p></blockquote><hr><h2 id="考试范围-十二模块-·-公开版本综合" tabindex="-1">考试范围（十二模块 · 公开版本综合） <a class="header-anchor" href="#考试范围-十二模块-·-公开版本综合" aria-label="Permalink to &quot;考试范围（十二模块 · 公开版本综合）&quot;">​</a></h2><ol><li><strong>函数与极限</strong>：映射与函数，数列/函数极限，无穷小大，运算法则，存在准则，两个重要极限，无穷小比较，连续与间断，闭区间性质</li><li><strong>导数与微分</strong>：定义，运算法则，高阶导，隐函数与参数方程，相关变化率，微分</li><li><strong>中值定理与导数应用</strong>：罗尔/拉格朗日，洛必达，泰勒，单调凹凸，极值最值，作图，曲率</li><li><strong>不定积分</strong>：概念性质，换元，分部，有理函数</li><li><strong>定积分</strong>：概念性质，N-L 公式，换元分部，反常积分</li><li><strong>定积分应用</strong>：元素法，几何/物理应用</li><li><strong>微分方程</strong>：可分离，齐次，一阶线性，可降阶，常系数线性</li><li><strong>向量与空间解析几何</strong>：向量运算，数量积向量积，平面直线，曲面曲线</li><li><strong>多元函数微分</strong>：偏导，全微分，复合与隐函数，极值</li><li><strong>重积分</strong>：二重（及三重）概念计算与应用</li><li><strong>曲线曲面积分</strong>：对弧长/坐标，格林公式等（以当年大纲深度为准）</li><li><strong>无穷级数</strong>：常数项审敛，幂级数，傅里叶级数</li></ol><hr><h2 id="与本库章节笔记对照" tabindex="-1">与本库章节笔记对照 <a class="header-anchor" href="#与本库章节笔记对照" aria-label="Permalink to &quot;与本库章节笔记对照&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">大纲模块</th><th style="text-align:left;">本库目录</th></tr></thead><tbody><tr><td style="text-align:left;">1 函数与极限</td><td style="text-align:left;">[[第一章 函数与极限]]</td></tr><tr><td style="text-align:left;">2–3 导数</td><td style="text-align:left;">[[第二章 一元函数微分学]]</td></tr><tr><td style="text-align:left;">4–6 积分</td><td style="text-align:left;">[[第三章 一元函数积分学]]</td></tr><tr><td style="text-align:left;">8 向量几何</td><td style="text-align:left;">[[第四章 向量与空间几何]]</td></tr><tr><td style="text-align:left;">9 多元微分</td><td style="text-align:left;">[[第五章 多元函数]]</td></tr><tr><td style="text-align:left;">10–11 重积分曲线积分</td><td style="text-align:left;">[[第六章 重积分与曲线积分]]</td></tr><tr><td style="text-align:left;">7 微分方程</td><td style="text-align:left;">[[第七章 常微分方程]]</td></tr><tr><td style="text-align:left;">12 级数</td><td style="text-align:left;">[[第八章 无穷级数]]</td></tr></tbody></table><hr><h2 id="备考权重经验-非官方" tabindex="-1">备考权重经验（非官方） <a class="header-anchor" href="#备考权重经验-非官方" aria-label="Permalink to &quot;备考权重经验（非官方）&quot;">​</a></h2><ul><li><strong>高频高分</strong>：极限、导数、积分计算</li><li><strong>稳定得分</strong>：微分方程一阶、多元偏导、二重积分</li><li><strong>看大纲深度</strong>：曲面积分、傅里叶等以当年要求为准</li></ul><p>返回：[[高等数学]]</p>',12)])])}const c=l(r,[["render",n]]);export{x as __pageData,c as default};
